        log(f"[VERIFY] Data format: {len(theta_df)} rows (expected ~400)")
        
        # Check for expected format (4 tests per participant)
        n_participants = theta_df['UID'].nunique()
        n_tests_per_uid = theta_df.groupby('UID')['test'].count()
        log(f"[VERIFY] {n_participants} unique participants")
        log(f"[VERIFY] Tests per participant: min={n_tests_per_uid.min()}, max={n_tests_per_uid.max()}")

