        # Expected output: DataFrame with participant-level theta statistics

        log("[ANALYSIS] Aggregating theta scores by participant...")
        
        # Calculate mean theta across all 4 tests per participant
        theta_summary = theta_df.groupby('UID').agg({
            'Theta_All': ['mean', 'std', 'count']
        }).round(4)
        
        # Flatten column names
        theta_summary.columns = ['theta_all', 'theta_SE', 'n_tests']
        theta_summary = theta_summary.reset_index()
        
        # Verify expected format
        if len(theta_summary) != 100:
            log(f"[WARNING] Expected 100 participants, got {len(theta_summary)}")
        
        if not all(theta_summary['n_tests'] == 4):
            log(f"[WARNING] Not all participants have 4 tests: {theta_summary['n_tests'].value_counts()}")
        
        # Check theta value bounds
        theta_min = theta_summary['theta_all'].min()
        theta_max = theta_summary['theta_all'].max()
        if not theta_summary['theta_all'].between(-3, 3).all():
            log(f"[WARNING] Some theta values outside expected range [-3, 3]: min={theta_min:.3f}, max={theta_max:.3f}")
        
        log(f"[ANALYSIS] Aggregation complete: {len(theta_summary)} participants")
        log(f"[ANALYSIS] Theta range: [{theta_min:.3f}, {theta_max:.3f}]")

